# LCS (longest common substring) length
def lcs_length(a,b):
    # longest common substring (not subsequence), dynamic programming
    n, m = len(a), len(b)
    dp = [[0]*(m+1) for _ in range(n+1)]
    maxlen = 0
    for i in range(n):
        for j in range(m):
            if a[i]==b[j]:
                dp[i+1][j+1] = dp[i][j]+1
                if dp[i+1][j+1] > maxlen:
                    maxlen = dp[i+1][j+1]
    return maxlen

